def form_valid(self, form):
        saved_objects = []
        args = [form.cleaned_data[field["field"]] for field in self.fields]
        for data in zip(*args):
            for field in self._get_ancestors_pointers(self.obj):
                setattr(self.obj, field, None)
            self.obj.id = self.obj.pk = None

            for field in self.clear_fields:
                setattr(self.obj, field["field"], field["value"])

            for i, field in enumerate(self.fields):
                setattr(self.obj, field["field"], data[i])

            try:
                self.obj.clean()
            except ValidationError as exc:
                for error in exc:
                    form.add_error(error[0], error[1])
                return self.form_invalid(form)

            self.obj.save()
            saved_objects.append(
                '<a href="{}">{}</a>'.format(self.obj.get_absolute_url(), str(self.obj))
            )

        messages.success(
            self.request,
            mark_safe(
                _("Saved %(count)d object(s): %(objects)s")
                % {"count": len(saved_objects), "objects": ", ".join(saved_objects)}
            ),
        )
        return HttpResponseRedirect(self.get_url_name())

def should_auto_retry(reg_info, registration):
    if not reg_info.get('can_be_reset', False):
        return False

    addon_list = reg_info.get('addon_list', [])
    complex_addons = set(addon_list) - {'osfstorage', 'wiki'}
    if complex_addons:
        logger.info(f"Registration {registration._id} has complex addons: {complex_addons}")
        return False

    logs_after_reg = reg_info.get('logs_on_original_after_registration_date', [])
    if logs_after_reg:
        logger.info(f"Registration {registration._id} has post-registration logs: {logs_after_reg}")
        return False

    successful_after = reg_info.get('succeeded_registrations_after_failed', [])
    if successful_after:
        logger.info(f"Registration {registration._id} has successful registrations after failure: {successful_after}")
        return False

    import django.utils.timezone as timezone
    from datetime import timedelta
    if registration.registered_date:
        age = timezone.now() - registration.registered_date
        if age > timedelta(days=30):
            logger.info(f"Registration {registration._id} is too old ({age.days} days)")
            return False
    return True

def get_node_contributors_abbrev(auth, node, **kwargs):
    anonymous = has_anonymous_link(node, auth)
    formatter = 'surname'
    max_count = kwargs.get('max_count', 3)
    if 'user_ids' in kwargs:
        users = [
            OSFUser.load(user_id) for user_id in kwargs['user_ids']
            if node.contributor_set.filter(user__guid__guid=user_id).exists()
        ]
    else:
        users = node.visible_contributors

    if anonymous or not node.can_view(auth):
        raise HTTPError(http_status.HTTP_403_FORBIDDEN)

    contributors = []

    n_contributors = len(users)
    others_count = ''

    for index, user in enumerate(users[:max_count]):

        if index == max_count - 1 and len(users) > max_count:
            separator = ' &'
            others_count = str(n_contributors - 3)
        elif index == len(users) - 1:
            separator = ''
        elif index == len(users) - 2:
            separator = ' &'
        else:
            separator = ','
        contributor = user.get_summary(formatter)
        contributor['user_id'] = user._primary_key
        contributor['separator'] = separator

        contributors.append(contributor)

    return {
        'contributors': contributors,
        'others_count': others_count,
    }

def edit_node(auth, node, **kwargs):
    post_data = request.json
    edited_field = post_data.get('name')
    value = post_data.get('value', '')

    new_val = None
    if edited_field == 'title':
        try:
            node.set_title(value, auth=auth)
        except ValidationError as e:
            raise HTTPError(
                http_status.HTTP_400_BAD_REQUEST,
                data=dict(message_long=str(e))
            )
        new_val = node.title
    elif edited_field == 'description':
        node.set_description(value, auth=auth)
        new_val = node.description
    elif edited_field == 'category':
        node.category = new_val = value

    try:
        node.save()
    except ValidationError as e:
        raise HTTPError(
            http_status.HTTP_400_BAD_REQUEST,
            data=dict(message_long=str(e))
        )
    return {
        'status': 'success',
        'newValue': new_val  # Used by x-editable  widget to reflect changes made by sanitizer
    }

def engagement_calendar(request):

    if not get_system_setting("enable_calendar"):
        raise Resolver404

    if "lead" not in request.GET or "0" in request.GET.getlist("lead"):
        engagements = get_authorized_engagements("view")
    else:
        filters = []
        leads = request.GET.getlist("lead", "")
        if "-1" in request.GET.getlist("lead"):
            leads.remove("-1")
            filters.append(Q(lead__isnull=True))
        filters.append(Q(lead__in=leads))
        engagements = get_authorized_engagements("view").filter(reduce(operator.or_, filters))

    engagements = engagements.select_related("lead")
    engagements = engagements.prefetch_related("product")

    for e in engagements:
        if e.target_end:
            e.target_end += timedelta(days=1)
    add_breadcrumb(
        title="Engagement Calendar", top_level=True, request=request)
    return render(
        request, "dojo/calendar.html", {
            "caltype": "engagements",
            "leads": request.GET.getlist("lead", ""),
            "engagements": engagements,
            "users": get_authorized_users("view"),
        })

