def handle(self, **kwargs):
        feed_urls = set(
            Feed.objects.filter(approval_status=APPROVED_FEED).values_list(
                "feed_url", flat=True
            )
        )

        subscribed_urls = set(Subscription.objects.values_list("topic", flat=True))

        missing_feeds = feed_urls - subscribed_urls
        extra_feeds = subscribed_urls - feed_urls

        for url in missing_feeds:
            logger.info(f"Subscribing to {url}")
            Subscription.objects.subscribe(url, settings.PUSH_HUB)

        for subscription in Subscription.objects.filter(topic__in=extra_feeds):
            logger.info(f"Unsubscribing from {subscription.pk} ({subscription.topic})")
            subscription.unsubscribe()

        limit = timezone.now() + timedelta(days=2)
        for subscription in Subscription.objects.exclude(topic__in=extra_feeds).filter(
            lease_expiration__lte=limit
        ):
            logger.info(
                f"Renewing subscription for {subscription.topic} ({subscription.pk})"
            )
            subscription.subscribe()

def rate_object(request, ct, pk, score=1, add=True):
    if request.method != "POST" and not ALLOW_GET:
        err_msg = f'Invalid request method: "{request.method}". Must be POST.'
        return HttpResponseNotAllowed(err_msg)

    redirect_url = (
        request.POST.get("next") or request.GET.get("next") or request.META.get("HTTP_REFERER")
    )
    if redirect_url and not url_has_allowed_host_and_scheme(redirect_url, settings.ALLOWED_HOSTS):
        return HttpResponseBadRequest("Invalid next URL.")
    if not redirect_url:
        redirect_url = "/"

    ctype = get_object_or_404(ContentType, pk=ct)
    model_class = ctype.model_class()

    if not hasattr(model_class, "_ratings_field"):
        err_msg = f"Model class {model_class} does not support ratings"
        raise Http404(err_msg)

    obj = get_object_or_404(model_class, pk=pk)

    ratings_descriptor = getattr(obj, obj._ratings_field)

    if add:
        ratings_descriptor.rate(request.user, score)
    else:
        ratings_descriptor.unrate(request.user)

    if request.is_ajax():
        return HttpResponse('{"success": true}', content_type="application/json")
    return HttpResponseRedirect(redirect_url)

def get_ipython(self, options):
        try:
            from IPython import start_ipython

            def run_ipython():
                imported_objects = self.get_imported_objects(options)
                ipython_arguments = self.extra_args or self.get_ipython_arguments(
                    options
                )
                start_ipython(argv=ipython_arguments, user_ns=imported_objects)

            return run_ipython
        except ImportError:
            str_exc = traceback.format_exc()
            # IPython < 0.11
            # Explicitly pass an empty list as arguments, because otherwise
            # IPython would use sys.argv from this script.
            # Notebook not supported for IPython < 0.11.
            try:
                from IPython.Shell import IPShell
            except ImportError:
                return str_exc + "\n" + traceback.format_exc()

            def run_ipython():
                imported_objects = self.get_imported_objects(options)
                shell = IPShell(argv=[], user_ns=imported_objects)
                shell.mainloop()

            return run_ipython

def to_internal_value(self, value):
        input_formats = getattr(self, 'input_formats', api_settings.DATE_INPUT_FORMATS)

        if isinstance(value, datetime.datetime):
            self.fail('datetime')

        if isinstance(value, datetime.date):
            return value

        for input_format in input_formats:
            if input_format.lower() == ISO_8601:
                try:
                    parsed = parse_date(value)
                except (ValueError, TypeError):
                    pass
                else:
                    if parsed is not None:
                        return parsed
            else:
                try:
                    parsed = self.datetime_parser(value, input_format)
                except (ValueError, TypeError):
                    pass
                else:
                    return parsed.date()

        humanized_format = humanize_datetime.date_formats(input_formats)
        self.fail('invalid', format=humanized_format)

def to_internal_value(self, data):
        request = self.context.get('request')
        try:
            http_prefix = data.startswith(('http:', 'https:'))
        except AttributeError:
            self.fail('incorrect_type', data_type=type(data).__name__)

        if http_prefix:
            # If needed convert absolute URLs to relative path
            data = parse.urlparse(data).path
            prefix = get_script_prefix()
            if data.startswith(prefix):
                data = '/' + data[len(prefix):]

        data = uri_to_iri(parse.unquote(data))

        try:
            match = resolve(data)
        except Resolver404:
            self.fail('no_match')

        try:
            expected_viewname = request.versioning_scheme.get_versioned_viewname(
                self.view_name, request
            )
        except AttributeError:
            expected_viewname = self.view_name

        if match.view_name != expected_viewname:
            self.fail('incorrect_match')

        try:
            return self.get_object(match.view_name, match.args, match.kwargs)
        except (ObjectDoesNotExist, ObjectValueError, ObjectTypeError):
            self.fail('does_not_exist')

def require_sudo_mode(f: ViewFunc) -> ViewFunc:
    @wraps(f)
    def wrapper(request: HttpRequest, *args: Any, **kwds: Any) -> HttpResponse:
        assert request.user.is_authenticated

        # is sudo mode active and has not expired yet?
        if _session_unsign(request, "sudo", 1800) == "active":
            return f(request, *args, **kwds)

        if not TokenBucket.authorize_sudo_code(request.user):
            return render(request, "try_later.html")

        # has the user submitted a code to enter sudo mode?
        if "sudo_code" in request.POST:
            ours = _session_unsign(request, "sudo_code", 900)
            if ours and ours == request.POST["sudo_code"]:
                request.session.pop("sudo_code")
                request.session["sudo"] = TimestampSigner().sign("active")
                return redirect(request.path)

        if not _session_unsign(request, "sudo_code", 900):
            code = "%06d" % secrets.randbelow(1000000)
            request.session["sudo_code"] = TimestampSigner().sign(code)
            emails.sudo_code(request.user.email, {"sudo_code": code})

        ctx = {}
        if "sudo_code" in request.POST:
            ctx["wrong_code"] = True

        return render(request, "accounts/sudo.html", ctx)

    return wrapper

def construct_response_model(self):
        assert self.request, 'Cant construct a response model if there is no request model'
        Logger.debug(
            'Creating response model for request model with pk %s'
            % self.request.pk
        )
        b, content = self.body()
        headers = {}
        for k, v in self.response.headers.items():
            try:
                header, val = v
            except ValueError:
                header, val = k, v
            finally:
                headers[header] = val
        silky_response = models.Response(
            request_id=self.request.id,
            status_code=self.response.status_code,
            encoded_headers=json.dumps(headers, ensure_ascii=SilkyConfig().SILKY_JSON_ENSURE_ASCII),
            body=b
        )

        try:
            raw_body = base64.b64encode(content)
        except TypeError:
            raw_body = base64.b64encode(content.encode('utf-8'))
        silky_response.raw_body = raw_body.decode('ascii')
        silky_response.save()
        return silky_response

def get(self, request, *_, **kwargs):
        request_id = kwargs.get('request_id')
        profile_id = kwargs.get('profile_id')
        try:
            per_page = int(request.GET.get('per_page', self.default_page_size))
        except (TypeError, ValueError):
            per_page = self.default_page_size
        context = {
            'request': request,
            'options_page_size': self.page_sizes,
            'per_page': per_page,
        }
        if request_id:
            silk_request = Request.objects.get(id=request_id)
            query_set = SQLQuery.objects.filter(request=silk_request).order_by('-start_time')
            for q in query_set:
                q.start_time_relative = q.start_time - silk_request.start_time
            page = _page(request, query_set, per_page)
            context['silk_request'] = silk_request
        if profile_id:
            p = Profile.objects.get(id=profile_id)
            page = _page(request, p.queries.order_by('-start_time').all(), per_page)
            context['profile'] = p
        if not (request_id or profile_id):
            raise KeyError('no profile_id or request_id')
        # noinspection PyUnboundLocalVariable
        context['items'] = page
        return render(request, 'silk/sql.html', context)

