def handle(self, *args, **options):
        # Nextcloud scan
        if options["nextcloud"]:
            self.nextcloud_scan()
            return

        # Add a single file.
        if options["scan_files"]:
            scan_files = options["scan_files"]
            deleted_user: User = get_deleted_user()
            for user in User.objects.all():
                user_files = []
                if user == deleted_user:
                    continue
                for scan_file in scan_files:
                    if scan_file.startswith(user.scan_directory):
                        user_files.append(scan_file)
                if user_files:
                    scan_photos(user, False, uuid.uuid4(), scan_files=user_files)
            return

        # Directory scan
        deleted_user: User = get_deleted_user()
        for user in User.objects.all():
            if user != deleted_user:
                scan_photos(
                    user, options["full_scan"], uuid.uuid4(), user.scan_directory
                )

def get_documents(self):
        WorkflowInstanceLogEntry = apps.get_model(
            app_label='document_states',
            model_name='WorkflowInstanceLogEntry'
        )

        latest_entries = WorkflowInstanceLogEntry.objects.annotate(
            max_datetime=Max(
                'workflow_instance__log_entries__datetime'
            )
        ).filter(
            datetime=F('max_datetime')
        )

        state_latest_entries = latest_entries.filter(
            transition__destination_state=self
        )

        return Document.valid.filter(
            Q(
                workflows__pk__in=state_latest_entries.values_list(
                    'workflow_instance', flat=True
                )
            ) | Q(
                workflows__log_entries__isnull=True,
                workflows__workflow__states=self,
                workflows__workflow__states__initial=True
            )
        ).distinct()

def task_source_process_document(source_id, dry_run=False):
    Source = apps.get_model(
        app_label='sources', model_name='Source'
    )

    lock_id = 'task_source_process_document-%d' % source_id
    try:
        logger.debug('trying to acquire lock: %s', lock_id)
        lock = LockingBackend.get_backend().acquire_lock(
            name=lock_id, timeout=DEFAULT_SOURCES_LOCK_EXPIRE
        )
    except LockError:
        logger.debug('unable to obtain lock: %s' % lock_id)
    else:
        logger.debug('acquired lock: %s', lock_id)

        try:
            source = Source.objects.get(pk=source_id)
            if source.enabled or dry_run:
                source.get_backend_instance().process_documents(dry_run=dry_run)
        except Exception as exception:
            logger.error(
                'Error processing source id: %s; %s', source_id, exception,
                exc_info=True
            )
            if settings.DEBUG:
                raise
            else:
                source.error_log.create(
                    text='{}; {}'.format(
                        exception.__class__.__name__, exception
                    )
                )
        else:
            source.error_log.all().delete()
        finally:
            lock.release()

def dummy_upload(request):
    if getattr(settings, 'ENV', None) == 'prod':
        raise PermissionDenied
    # dd if=/dev/urandom of=/tmp/test.img bs=100M count=1
    # curl -F parse=1 -F upload=@/tmp/test.img <host>/services/dummy_upload
    if request.POST.get('parse') and 'upload' in request.FILES:
        buf = request.FILES['upload'].read()
    else:
        buf = ''
    # Additional delay to test timeout behavior.
    if 'delay' in request.POST:
        try:
            delay = int(request.POST.get('delay', 1))
            if delay > 120 or delay < 0:
                raise ValueError
        except ValueError:
            delay = 1
        time.sleep(delay)
    else:
        delay = None

    return JsonResponse(
        {
            # request._start_time is set by GraphiteRequestTimingMiddleware
            'elapsed_in_app': int((time.time() - request._start_time) * 1000),
            'buf_size': len(buf),
            'delay': delay,
        }
    )

def get_token_value(self, request):
        auth_header = get_authorization_header(request).split()
        expected_header_prefix = self.auth_header_prefix.upper()

        if not auth_header or (
            smart_str(auth_header[0].upper()) != expected_header_prefix
        ):
            return None

        if len(auth_header) == 1:
            msg = {
                'detail': gettext(
                    'Invalid Authorization header. No credentials provided.'
                ),
                'code': 'ERROR_INVALID_HEADER',
            }
            raise exceptions.AuthenticationFailed(msg)
        elif len(auth_header) > 2:
            msg = {
                'detail': gettext(
                    'Invalid Authorization header. Credentials string should not '
                    'contain spaces.'
                ),
                'code': 'ERROR_INVALID_HEADER',
            }
            raise exceptions.AuthenticationFailed(msg)

        return auth_header[1]

def resolve_filter(self, info, **kwargs):
        field = getattr(self, field_name)

        if not filterset_class or not kwargs:
            return field.all()

        # Backwards-compatibility with Nautobot v2 - "_type" as a (now deprecated) alias for "type" filter
        if "_type" in kwargs:
            _type = kwargs.pop("_type")
            if "type" not in kwargs:
                kwargs["type"] = _type

        if not hasattr(info.context, "_gql_filter_cache"):
            info.context._gql_filter_cache = {}

        related_model = field.model
        cache_key = (related_model._meta.label, field_name, _make_filter_cache_key(kwargs))

        if cache_key not in info.context._gql_filter_cache:
            resolved_obj = filterset_class(kwargs, related_model.objects.all())

            if resolved_obj.errors:
                raise GraphQLError(str(dict(resolved_obj.errors)))

            # Cache the filterset evaluation per request to avoid N+1 queries.
            info.context._gql_filter_cache[cache_key] = set(resolved_obj.qs.values_list("pk", flat=True))

        matching_ids = info.context._gql_filter_cache[cache_key]
        return [obj for obj in field.all() if obj.pk in matching_ids]
